using System;
using System.Collections.Generic;
using System.Reflection;
using System.Linq;

// Load assemblies
var assemblyPaths = new[]
{
    "/home/runner/.nuget/packages/microsoft.agents.ai/1.3.0/lib/net8.0/Microsoft.Agents.AI.dll",
    "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.0/lib/net8.0/Microsoft.Extensions.AI.dll"
};

var assemblies = new List<Assembly>();
foreach (var path in assemblyPaths)
{
    try
    {
        assemblies.Add(Assembly.LoadFrom(path));
        Console.WriteLine($"✓ Loaded: {path}");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"✗ Failed to load {path}: {ex.Message}");
    }
}

Console.WriteLine("\n" + new string('=', 80));
Console.WriteLine("AGENT CREATION CLASSES");
Console.WriteLine(new string('=', 80) + "\n");

// Look for agent-related classes
var agentTypes = assemblies.SelectMany(a => a.GetTypes())
    .Where(t => t.IsClass && !t.IsAbstract && (
        t.Name.Contains("Agent") || 
        t.Name.Contains("Worker") ||
        t.Name.Contains("Client")))
    .OrderBy(t => t.FullName)
    .ToList();

foreach (var type in agentTypes)
{
    Console.WriteLine($"\n📌 {type.FullName}");

    // Constructors
    var constructors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
    if (constructors.Length > 0)
    {
        Console.WriteLine("  Constructors:");
        foreach (var ctor in constructors)
        {
            var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    - ({parms})");
        }
    }

    // Key methods
    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName && !m.IsProperty())
        .ToList();

    if (methods.Count > 0)
    {
        Console.WriteLine("  Methods:");
        foreach (var method in methods.Take(10))
        {
            var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    - {method.ReturnType.Name} {method.Name}({parms})");
        }
        if (methods.Count > 10)
            Console.WriteLine($"    ... and {methods.Count - 10} more");
    }
}

